module reg_file(
    input                 clk,
    input                 rst,
    input                 we,
    input       [1:0]     waddr,
    input       [7:0]     wdata,
    input       [1:0]     raddr1,
    input       [1:0]     raddr2,
    output   reg [7:0]    rdata1,
    output   reg [7:0]    rdata2
);

reg [7:0] mem [0:3];  // 4 mem of 8 bits each

// Write logic
always @(posedge clk or posedge rst) begin
    if (rst) begin
        mem[0] <= 8'd0;
        mem[1] <= 8'd0;
        mem[2] <= 8'd0;
        mem[3] <= 8'd0;
    end else if (we) begin
        mem[waddr] <= wdata;
    end
end

// Read logic
always @(*) begin
    rdata1 = mem[raddr1];
    rdata2 = mem[raddr2];
end

endmodule
